use std::collections::HashMap;
use std::fs;
use std::path::{Path, PathBuf};
use std::process;

use clap::Parser;
use cli_lib::js_executor::JsExecutor;
use compiler_lib::{CompilationResult, FileProvider, State};
use similar::TextDiff;

#[derive(Parser)]
#[command(name = "test_runner")]
#[command(about = "Integration test runner for 1SubML")]
struct Args {
    /// Test files or directories to run
    paths: Vec<PathBuf>,

    /// Update expected outputs to match actual outputs
    #[arg(long)]
    update: bool,

    /// Directory to cache JS execution results
    #[arg(long, env = "ONESUBML_CACHE_DIR")]
    cache_dir: Option<PathBuf>,
}

enum TestCase {
    Single {
        code: String,
        expected: String,
    },
    MultiFile {
        main_code: String,
        files: Vec<(String, String)>,
        expected: String,
    },
    Repl {
        sections: Vec<(String, String)>,
    },
}

struct MapFileProvider {
    files: HashMap<String, String>,
}
impl FileProvider for MapFileProvider {
    fn get_file(&mut self, module_path: &str) -> Result<String, String> {
        self.files
            .get(module_path)
            .cloned()
            .ok_or_else(|| format!("Module not found: {}", module_path))
    }
}

fn parse_test_file(content: &str) -> TestCase {
    let lines: Vec<&str> = content.lines().collect();

    // Check for REPL test
    if lines.first() == Some(&"#### REPL") {
        return parse_repl_test(&lines[1..]);
    }

    // Split on #### lines
    let mut segments: Vec<(Option<&str>, String)> = Vec::new();
    let mut current_lines: Vec<&str> = Vec::new();
    let mut current_header: Option<&str> = None;
    let mut first = true;

    for line in &lines {
        if let Some(rest) = line.strip_prefix("####") {
            if !first || !current_lines.is_empty() {
                segments.push((current_header, current_lines.join("\n")));
            }
            let rest = rest.trim();
            current_header = if rest.is_empty() { None } else { Some(rest) };
            current_lines = Vec::new();
            first = false;
        } else {
            current_lines.push(line);
        }
    }
    if !first {
        segments.push((current_header, current_lines.join("\n")));
    }

    // Determine test type from segments
    if segments.is_empty() {
        // No separator found — treat entire content as code with empty expected
        return TestCase::Single {
            code: content.to_string(),
            expected: String::new(),
        };
    }

    // Check if any segment has a .ml header → MultiFile
    let has_ml_files = segments.iter().any(|(h, _)| h.map_or(false, |h| h.ends_with(".ml")));

    if has_ml_files {
        // First segment (before any ####) is main code
        let main_code = lines
            .iter()
            .take_while(|l| !l.starts_with("####"))
            .copied()
            .collect::<Vec<_>>()
            .join("\n");

        let mut files = Vec::new();
        let mut expected = String::new();

        for (header, body) in &segments {
            match header {
                Some(h) if h.ends_with(".ml") => {
                    let module = h.strip_suffix(".ml").unwrap().to_string();
                    files.push((module, body.clone()));
                }
                _ => {
                    expected = body.clone();
                }
            }
        }

        TestCase::MultiFile {
            main_code,
            files,
            expected,
        }
    } else {
        // Single test: code before first ####, expected after
        let code = lines
            .iter()
            .take_while(|l| !l.starts_with("####"))
            .copied()
            .collect::<Vec<_>>()
            .join("\n");
        let expected = segments.last().map(|(_, b)| b.clone()).unwrap_or_default();

        TestCase::Single { code, expected }
    }
}

fn parse_repl_test(lines: &[&str]) -> TestCase {
    // After "#### REPL", we have alternating: code, ####, expected, #### INPUT, code, ####, expected, ...
    let mut sections: Vec<(String, String)> = Vec::new();
    let mut current_lines: Vec<&str> = Vec::new();
    let mut parts: Vec<String> = Vec::new();

    // Collect parts split by #### lines
    // First part is the initial code
    for line in lines {
        if *line == "####" || line.starts_with("#### ") {
            parts.push(current_lines.join("\n"));
            current_lines = Vec::new();
            // If it's "#### INPUT", the next part is a new input
            // If it's "####", the next part is expected output
            // We track this by noting: parts alternate code, expected, code, expected...
            // But we need to handle the #### INPUT markers
        } else {
            current_lines.push(line);
        }
    }
    parts.push(current_lines.join("\n"));

    // Parts should be: code, expected, code, expected, ...
    // (#### starts expected, #### INPUT starts code)
    // Let's re-parse more carefully
    sections.clear();
    let mut code_lines: Vec<&str> = Vec::new();
    let mut expecting_output = false;
    let mut expected_lines: Vec<&str> = Vec::new();

    for line in lines {
        if *line == "####" {
            if expecting_output {
                // End of expected output + start of next expected? Shouldn't happen.
                // This means we finished an expected section without INPUT
                sections.push((code_lines.join("\n"), expected_lines.join("\n")));
                code_lines = Vec::new();
                expected_lines = Vec::new();
                // Stay in expecting_output = false? No, #### alone means start expected
                expecting_output = true;
            } else {
                // Start of expected output
                expecting_output = true;
            }
        } else if *line == "#### INPUT" {
            if expecting_output {
                // Save previous section
                sections.push((code_lines.join("\n"), expected_lines.join("\n")));
                code_lines = Vec::new();
                expected_lines = Vec::new();
                expecting_output = false;
            }
        } else if expecting_output {
            expected_lines.push(line);
        } else {
            code_lines.push(line);
        }
    }
    // Save last section
    if !code_lines.is_empty() || !expected_lines.is_empty() {
        sections.push((code_lines.join("\n"), expected_lines.join("\n")));
    }

    TestCase::Repl { sections }
}

enum TestResult {
    Pass,
    Fail {
        section: Option<usize>, // None for single/multi, Some(i) for REPL
        expected: String,
        actual: String,
    },
    MultiFail(Vec<(usize, String, String)>), // REPL with multiple failures
}

fn run_test(test: &TestCase, js_executor: &JsExecutor) -> TestResult {
    match test {
        TestCase::Single { code, expected } => {
            let mut state = State::new();
            let mut files = MapFileProvider { files: HashMap::new() };
            let actual = run_compilation(&mut state, code, &mut files, js_executor);
            compare(&actual, expected, None)
        }
        TestCase::MultiFile {
            main_code,
            files,
            expected,
        } => {
            let mut state = State::new();
            let file_map: HashMap<String, String> = files.iter().cloned().collect();
            let mut provider = MapFileProvider { files: file_map };
            let actual = run_compilation(&mut state, main_code, &mut provider, js_executor);
            compare(&actual, expected, None)
        }
        TestCase::Repl { sections } => {
            let mut state = State::new();
            let mut files = MapFileProvider { files: HashMap::new() };
            let mut accumulated_js: Vec<String> = Vec::new();
            let mut prev_output = String::new();
            let mut failures: Vec<(usize, String, String)> = Vec::new();

            for (i, (code, expected)) in sections.iter().enumerate() {
                let result = state.process(code, &mut files);
                let actual = match result {
                    CompilationResult::Error(msg) => msg,
                    CompilationResult::Success(js) => {
                        accumulated_js.push(js);
                        let full_js = accumulated_js.join("\n");
                        match js_executor.execute_js(&full_js) {
                            Ok(output) => {
                                let output = output.trim_end().to_string();
                                let new_output = if prev_output.is_empty() {
                                    output.clone()
                                } else if output.starts_with(&prev_output) {
                                    output[prev_output.len()..].trim_start_matches('\n').to_string()
                                } else {
                                    output.clone()
                                };
                                prev_output = output;
                                new_output
                            }
                            Err(e) => format!("JS execution error: {}", e),
                        }
                    }
                };

                let actual = actual.trim_end().to_string();
                let expected = expected.trim_end().to_string();
                if actual != expected {
                    failures.push((i + 1, expected, actual));
                }
            }

            if failures.is_empty() {
                TestResult::Pass
            } else if failures.len() == 1 {
                let (section, expected, actual) = failures.into_iter().next().unwrap();
                TestResult::Fail {
                    section: Some(section),
                    expected,
                    actual,
                }
            } else {
                TestResult::MultiFail(failures)
            }
        }
    }
}

fn run_compilation(state: &mut State, code: &str, files: &mut MapFileProvider, js_executor: &JsExecutor) -> String {
    let result = state.process(code, files);
    match result {
        CompilationResult::Error(msg) => msg.trim_end().to_string(),
        CompilationResult::Success(js) => match js_executor.execute_js(&js) {
            Ok(output) => output.trim_end().to_string(),
            Err(e) => format!("JS execution error: {}", e),
        },
    }
}

fn compare(actual: &str, expected: &str, section: Option<usize>) -> TestResult {
    let actual = actual.trim_end();
    let expected = expected.trim_end();
    if actual == expected {
        TestResult::Pass
    } else {
        TestResult::Fail {
            section,
            expected: expected.to_string(),
            actual: actual.to_string(),
        }
    }
}

fn print_diff(expected: &str, actual: &str) {
    let diff = TextDiff::from_lines(expected, actual);
    let udiff = diff.unified_diff().header("expected", "actual").to_string();
    for line in udiff.lines() {
        println!("    {}", line);
    }
}

fn collect_test_files(paths: &[PathBuf]) -> Vec<PathBuf> {
    let mut files = Vec::new();
    for path in paths {
        if path.is_dir() {
            if let Ok(entries) = fs::read_dir(path) {
                let mut dir_files: Vec<PathBuf> = entries
                    .filter_map(|e| e.ok())
                    .map(|e| e.path())
                    .filter(|p| p.extension().is_some_and(|e| e == "test"))
                    .collect();
                dir_files.sort();
                files.extend(dir_files);
            }
        } else {
            files.push(path.clone());
        }
    }
    files
}

fn update_test_file(path: &Path, test: &TestCase, js_executor: &JsExecutor) -> bool {
    let new_content = match test {
        TestCase::Single { code, .. } => {
            let mut state = State::new();
            let mut files = MapFileProvider { files: HashMap::new() };
            let actual = run_compilation(&mut state, code, &mut files, js_executor);
            format!("{}\n####\n{}\n", code, actual)
        }
        TestCase::MultiFile { main_code, files, .. } => {
            let mut state = State::new();
            let file_map: HashMap<String, String> = files.iter().cloned().collect();
            let mut provider = MapFileProvider { files: file_map };
            let actual = run_compilation(&mut state, main_code, &mut provider, js_executor);

            let mut content = main_code.clone();
            for (name, body) in files {
                content.push_str(&format!("\n#### {}.ml\n{}", name, body));
            }
            content.push_str(&format!("\n####\n{}\n", actual));
            content
        }
        TestCase::Repl { sections } => {
            let mut state = State::new();
            let mut files = MapFileProvider { files: HashMap::new() };
            let mut accumulated_js: Vec<String> = Vec::new();
            let mut prev_output = String::new();
            let mut content = String::from("#### REPL\n");

            for (i, (code, _)) in sections.iter().enumerate() {
                if i > 0 {
                    content.push_str("#### INPUT\n");
                }
                content.push_str(code);
                content.push('\n');

                let result = state.process(code, &mut files);
                let actual = match result {
                    CompilationResult::Error(msg) => msg,
                    CompilationResult::Success(js) => {
                        accumulated_js.push(js);
                        let full_js = accumulated_js.join("\n");
                        match js_executor.execute_js(&full_js) {
                            Ok(output) => {
                                let output = output.trim_end().to_string();
                                let new_output = if prev_output.is_empty() {
                                    output.clone()
                                } else if output.starts_with(&prev_output) {
                                    output[prev_output.len()..].trim_start_matches('\n').to_string()
                                } else {
                                    output.clone()
                                };
                                prev_output = output;
                                new_output
                            }
                            Err(e) => format!("JS execution error: {}", e),
                        }
                    }
                };

                content.push_str("####\n");
                content.push_str(actual.trim_end());
                content.push('\n');
            }

            content
        }
    };

    let old_content = fs::read_to_string(path).unwrap_or_default();
    if old_content != new_content {
        fs::write(path, &new_content).unwrap();
        true
    } else {
        false
    }
}

fn main() {
    let args = Args::parse();
    let js_executor = JsExecutor::new(args.cache_dir);
    let test_files = collect_test_files(&args.paths);

    if test_files.is_empty() {
        eprintln!("No test files found");
        process::exit(1);
    }

    if args.update {
        // Update mode
        let mut updated = 0;
        for path in &test_files {
            let content = fs::read_to_string(path).unwrap();
            let test = parse_test_file(&content);
            if update_test_file(path, &test, &js_executor) {
                println!("  UPDATED  {}", path.display());
                updated += 1;
            } else {
                println!("  OK       {}", path.display());
            }
        }
        println!("\n{} files, {} updated", test_files.len(), updated);
    } else {
        // Run mode
        println!("Running {} tests...", test_files.len());
        let mut passed = 0;
        let mut failed = 0;

        for path in &test_files {
            let content = fs::read_to_string(path).unwrap();
            let test = parse_test_file(&content);
            let result = run_test(&test, &js_executor);

            match result {
                TestResult::Pass => {
                    println!("  PASS  {}", path.display());
                    passed += 1;
                }
                TestResult::Fail {
                    section,
                    expected,
                    actual,
                } => {
                    if let Some(s) = section {
                        println!("  FAIL  {} (section {})", path.display(), s);
                    } else {
                        println!("  FAIL  {}", path.display());
                    }
                    print_diff(&expected, &actual);
                    failed += 1;
                }
                TestResult::MultiFail(failures) => {
                    let sections: Vec<String> = failures.iter().map(|(s, _, _)| s.to_string()).collect();
                    println!("  FAIL  {} (sections {})", path.display(), sections.join(", "));
                    for (section, expected, actual) in &failures {
                        println!("    Section {}:", section);
                        print_diff(expected, actual);
                    }
                    failed += 1;
                }
            }
        }

        println!("\n{} tests, {} passed, {} failed", passed + failed, passed, failed);
        if failed > 0 {
            process::exit(1);
        }
    }
}
